     3→const {
     4→  ArrayPrototypeJoin,
     5→  ArrayPrototypeMap,
     6→  ArrayPrototypeReduce,
     7→  FunctionPrototypeCall,
     8→  JSONStringify,
     9→  ObjectSetPrototypeOf,
    10→  RegExpPrototypeSymbolReplace,
    11→  encodeURIComponent,
    12→  hardenRegExp,
    13→} = primordials;
    14→
    15→
    16→// This is needed to avoid cycles in esm/resolve <-> cjs/loader
    17→const {
    18→  kIsExecuting,
    19→  kRequiredModuleSymbol,
    20→} = require('internal/modules/cjs/loader');
    21→
    22→const { imported_cjs_symbol } = internalBinding('symbols');
    23→
    24→const assert = require('internal/assert');
    25→const {
    26→  ERR_REQUIRE_ASYNC_MODULE,
    27→  ERR_REQUIRE_CYCLE_MODULE,
    28→  ERR_REQUIRE_ESM,
    29→  ERR_NETWORK_IMPORT_DISALLOWED,
    30→  ERR_UNKNOWN_MODULE_FORMAT,
    31→} = require('internal/errors').codes;
    32→const { getOptionValue } = require('internal/options');
    33→const { isURL, pathToFileURL, URLParse } = require('internal/url');
    34→const { kEmptyObject } = require('internal/util');
    35→const {
    36→  compileSourceTextModule,
    37→  getDefaultConditions,
    38→  forceDefaultLoader,
    39→} = require('internal/modules/esm/utils');
    40→const { kImplicitTypeAttribute } = require('internal/modules/esm/assert');
    41→const { ModuleWrap, kEvaluating, kEvaluated } = internalBinding('module_wrap');
    42→const {
    43→  urlToFilename,
    44→} = require('internal/modules/helpers');
    45→let defaultResolve, defaultLoad, defaultLoadSync, importMetaInitializer;
    46→
    47→const { tracingChannel } = require('diagnostics_channel');
    48→const onImport = tracingChannel('module.import');
    49→
    50→/**
    51→ * @typedef {import('url').URL} URL
    52→ */
    53→
    54→/**
    55→ * Lazy loads the module_map module and returns a new instance of ResolveCache.
    56→ * @returns {import('./module_map.js').ResolveCache}
    57→ */
    58→function newResolveCache() {
    59→  const { ResolveCache } = require('internal/modules/esm/module_map');
    60→  return new ResolveCache();
    61→}
    62→
    63→/**
    64→ * Generate a load cache (to store the final result of a load-chain for a particular module).
    65→ * @returns {import('./module_map.js').LoadCache}
    66→ */
    67→function newLoadCache() {
    68→  const { LoadCache } = require('internal/modules/esm/module_map');
    69→  return new LoadCache();
    70→}
    71→
    72→/**
    73→ * Lazy-load translators to avoid potentially unnecessary work at startup (ex if ESM is not used).
    74→ * @returns {import('./translators.js').Translators}
    75→ */
    76→function getTranslators() {
    77→  const { translators } = require('internal/modules/esm/translators');
    78→  return translators;
    79→}
    80→
    81→/**
    82→ * @type {HooksProxy}
    83→ * Multiple loader instances exist for various, specific reasons (see code comments at site).
    84→ * In order to maintain consistency, we use a single worker (sandbox), which must sit apart of an
    85→ * individual loader instance.
    86→ */
    87→let hooksProxy;
    88→
    89→/**
    90→ * @typedef {import('../cjs/loader.js').Module} CJSModule
    91→ */
    92→
    93→/**
    94→ * @typedef {Record<string, any>} ModuleExports
    95→ */
    96→
    97→/**
    98→ * @typedef {'builtin'|'commonjs'|'json'|'module'|'wasm'} ModuleFormat
    99→ */
   100→
   101→/**
   102→ * @typedef {ArrayBuffer|TypedArray|string} ModuleSource
   103→ */
   104→
   105→/**
   106→ * This class covers the base machinery of module loading. To add custom
   107→ * behavior you can pass a customizations object and this object will be
   108→ * used to do the loading/resolving/registration process.
   109→ */
   110→class ModuleLoader {
   111→  /**
   112→   * The conditions for resolving packages if `--conditions` is not used.
   113→   */
   114→  #defaultConditions = getDefaultConditions();
   115→
   116→  /**
   117→   * Registry of resolved specifiers
   118→   */
   119→  #resolveCache = newResolveCache();
   120→
   121→  /**
   122→   * Registry of loaded modules, akin to `require.cache`
   123→   */
   124→  loadCache = newLoadCache();
   125→
   126→  /**
   127→   * Methods which translate input code or other information into ES modules
   128→   */
   129→  translators = getTranslators();
   130→
   131→  /**
   132→   * Truthy to allow the use of `import.meta.resolve`. This is needed
   133→   * currently because the `Hooks` class does not have `resolveSync`
   134→   * implemented and `import.meta.resolve` requires it.
   135→   */
   136→  allowImportMetaResolve;
   137→
   138→  /**
   139→   * Customizations to pass requests to.
   140→   *
   141→   * Note that this value _MUST_ be set with `setCustomizations`
   142→   * because it needs to copy `customizations.allowImportMetaResolve`
   143→   *  to this property and failure to do so will cause undefined
   144→   * behavior when invoking `import.meta.resolve`.
   145→   * @see {ModuleLoader.setCustomizations}
   146→   */
   147→  #customizations;
   148→
   149→  constructor(customizations) {
   150→    this.setCustomizations(customizations);
   151→  }
   152→
   153→  /**
   154→   * Change the currently activate customizations for this module
   155→   * loader to be the provided `customizations`.
   156→   *
   157→   * If present, this class customizes its core functionality to the
   158→   * `customizations` object, including registration, loading, and resolving.
   159→   * There are some responsibilities that this class _always_ takes
   160→   * care of, like validating outputs, so that the customizations object
   161→   * does not have to do so.
   162→   *
   163→   * The customizations object has the shape:
   164→   *
   165→   * ```ts
   166→   * interface LoadResult {
   167→   *   format: ModuleFormat;
   168→   *   source: ModuleSource;
   169→   * }
   170→   *
   171→   * interface ResolveResult {
   172→   *   format: string;
   173→   *   url: URL['href'];
   174→   * }
   175→   *
   176→   * interface Customizations {
   177→   *   allowImportMetaResolve: boolean;
   178→   *   load(url: string, context: object): Promise<LoadResult>
   179→   *   resolve(
   180→   *     originalSpecifier:
   181→   *     string, parentURL: string,
   182→   *     importAttributes: Record<string, string>
   183→   *   ): Promise<ResolveResult>
   184→   *   resolveSync(
   185→   *     originalSpecifier:
   186→   *     string, parentURL: string,
   187→   *     importAttributes: Record<string, string>
   188→   *   ) ResolveResult;
   189→   *   register(specifier: string, parentURL: string): any;
   190→   *   forceLoadHooks(): void;
   191→   * }
   192→   * ```
   193→   *
   194→   * Note that this class _also_ implements the `Customizations`
   195→   * interface, as does `CustomizedModuleLoader` and `Hooks`.
   196→   *
   197→   * Calling this function alters how modules are loaded and should be
   198→   * invoked with care.
   199→   * @param {object} customizations
   200→   */
   201→  setCustomizations(customizations) {
   202→    this.#customizations = customizations;
   203→    if (customizations) {
   204→      this.allowImportMetaResolve = customizations.allowImportMetaResolve;
   205→    } else {
   206→      this.allowImportMetaResolve = true;
   207→    }
   208→  }
   209→
   210→  async eval(source, url, isEntryPoint = false) {
   211→    const { ModuleJob } = require('internal/modules/esm/module_job');
   212→    const wrap = compileSourceTextModule(url, source, this);
   213→    const module = await onImport.tracePromise(async () => {
   214→      const job = new ModuleJob(
   215→        this, url, undefined, wrap, false, false);
   216→      this.loadCache.set(url, undefined, job);
   217→      const { module } = await job.run(isEntryPoint);
   218→      return module;
   219→    }, {
   220→      __proto__: null,
   221→      parentURL: '<eval>',
   222→      url,
   223→    });
   224→
   225→    return {
   226→      __proto__: null,
   227→      namespace: module.getNamespace(),
   228→      module,
   229→    };
   230→  }
   231→
   232→  /**
   233→   * Get a (possibly not yet fully linked) module job from the cache, or create one and return its Promise.
   234→   * @param {string} specifier The module request of the module to be resolved. Typically, what's
   235→   *                           requested by `import '<specifier>'` or `import('<specifier>')`.
   236→   * @param {string} [parentURL] The URL of the module where the module request is initiated.
   237→   *                             It's undefined if it's from the root module.
   238→   * @param {ImportAttributes} importAttributes Attributes from the import statement or expression.
   239→   * @returns {Promise<ModuleJobBase}
   240→   */
   241→  async getModuleJobForImport(specifier, parentURL, importAttributes) {
   242→    const resolveResult = await this.resolve(specifier, parentURL, importAttributes);
   243→    return this.#getJobFromResolveResult(resolveResult, parentURL, importAttributes, false);
   244→  }
   245→
   246→  /**
   247→   * Similar to {@link getModuleJobForImport} but it's used for `require()` resolved by the ESM loader
   248→   * in imported CJS modules. This runs synchronously and when it returns, the module job's module
   249→   * requests are all linked.
   250→   * @param {string} specifier See {@link getModuleJobForImport}
   251→   * @param {string} [parentURL] See {@link getModuleJobForImport}
   252→   * @param {ImportAttributes} importAttributes See {@link getModuleJobForImport}
   253→   * @returns {Promise<ModuleJobBase}
   254→   */
   255→  getModuleJobForRequireInImportedCJS(specifier, parentURL, importAttributes) {
   256→    const resolveResult = this.resolveSync(specifier, parentURL, importAttributes);
   257→    return this.#getJobFromResolveResult(resolveResult, parentURL, importAttributes, true);
   258→  }
   259→
   260→  /**
   261→   * Given a resolved module request, obtain a ModuleJobBase from it - if it's already cached,
   262→   * return the cached ModuleJobBase. Otherwise, load its source and translate it into a ModuleWrap first.
   263→   * @param {{ format: string, url: string }} resolveResult Resolved module request.
   264→   * @param {string} [parentURL] See {@link getModuleJobForImport}
   265→   * @param {ImportAttributes} importAttributes See {@link getModuleJobForImport}
   266→   * @param {boolean} isForRequireInImportedCJS Whether this is done for require() in imported CJS.
   267→   * @returns {ModuleJobBase}
   268→   */
   269→  #getJobFromResolveResult(resolveResult, parentURL, importAttributes, isForRequireInImportedCJS = false) {
   270→    const { url, format } = resolveResult;
   271→    const resolvedImportAttributes = resolveResult.importAttributes ?? importAttributes;
   272→    let job = this.loadCache.get(url, resolvedImportAttributes.type);
   273→
   274→    if (job === undefined) {
   275→      job = this.#createModuleJob(url, resolvedImportAttributes, parentURL, format, isForRequireInImportedCJS);
   276→    }
   277→
   278→    return job;
   279→  }
   280→
   281→  /**
   282→   * This constructs (creates, instantiates and evaluates) a module graph that
   283→   * is require()'d.
   284→   * @param {CJSModule} mod CJS module wrapper of the ESM.
   285→   * @param {string} filename Resolved filename of the module being require()'d
   286→   * @param {string} source Source code. TODO(joyeecheung): pass the raw buffer.
   287→   * @param {string} isMain Whether this module is a main module.
   288→   * @param {CJSModule|undefined} parent Parent module, if any.
   289→   * @returns {{wrap: ModuleWrap, namespace: ModuleNamespaceObject}}
   290→   */
   291→  importSyncForRequire(mod, filename, source, isMain, parent) {
   292→    const url = pathToFileURL(filename).href;
   293→    let job = this.loadCache.get(url, kImplicitTypeAttribute);
   294→    // This module job is already created:
   295→    // 1. If it was loaded by `require()` before, at this point the instantiation
   296→    //    is already completed and we can check the whether it is in a cycle
   297→    //    (in that case the module status is kEvaluaing), and whether the
   298→    //    required graph is synchronous.
   299→    // 2. If it was loaded by `import` before, only allow it if it's already evaluated
   300→    //    to forbid cycles.
   301→    //    TODO(joyeecheung): ensure that imported synchronous graphs are evaluated
   302→    //    synchronously so that any previously imported synchronous graph is already
   303→    //    evaluated at this point.
   304→    if (job !== undefined) {
   305→      mod[kRequiredModuleSymbol] = job.module;
   306→      if (job.module.async) {
   307→        throw new ERR_REQUIRE_ASYNC_MODULE();
   308→      }
   309→      if (job.module.getStatus() !== kEvaluated) {
   310→        const parentFilename = urlToFilename(parent?.filename);
   311→        let message = `Cannot require() ES Module ${filename} in a cycle.`;
   312→        if (parentFilename) {
   313→          message += ` (from ${parentFilename})`;
   314→        }
   315→        throw new ERR_REQUIRE_CYCLE_MODULE(message);
   316→      }
   317→      return { wrap: job.module, namespace: job.module.getNamespaceSync() };
   318→    }
   319→    // TODO(joyeecheung): refactor this so that we pre-parse in C++ and hit the
   320→    // cache here, or use a carrier object to carry the compiled module script
   321→    // into the constructor to ensure cache hit.
   322→    const wrap = compileSourceTextModule(url, source, this);
   323→    const inspectBrk = (isMain && getOptionValue('--inspect-brk'));
   324→
   325→    const { ModuleJobSync } = require('internal/modules/esm/module_job');
   326→    job = new ModuleJobSync(this, url, kEmptyObject, wrap, isMain, inspectBrk);
   327→    this.loadCache.set(url, kImplicitTypeAttribute, job);
   328→    mod[kRequiredModuleSymbol] = job.module;
   329→    return { wrap: job.module, namespace: job.runSync().namespace };
   330→  }
   331→
   332→  /**
   333→   * Resolve individual module requests and create or get the cached ModuleWraps for
   334→   * each of them. This is only used to create a module graph being require()'d.
   335→   * @param {string} specifier Specifier of the the imported module.
   336→   * @param {string} parentURL Where the import comes from.
   337→   * @param {object} importAttributes import attributes from the import statement.
   338→   * @returns {ModuleJobBase}
   339→   */
   340→  getModuleJobForRequire(specifier, parentURL, importAttributes) {
   341→    const parsed = URLParse(specifier);
   342→    if (parsed != null) {
   343→      const protocol = parsed.protocol;
   344→      if (protocol === 'https:' || protocol === 'http:') {
   345→        throw new ERR_NETWORK_IMPORT_DISALLOWED(specifier, parentURL,
   346→                                                'ES modules cannot be loaded by require() from the network');
   347→      }
   348→      assert(protocol === 'file:' || protocol === 'node:' || protocol === 'data:');
   349→    }
   350→
   351→    // TODO(joyeecheung): consolidate cache behavior and use resolveSync() and
   352→    // loadSync() here.
   353→    const resolveResult = this.#cachedDefaultResolve(specifier, parentURL, importAttributes);
   354→    const { url, format } = resolveResult;
   355→    if (!getOptionValue('--experimental-require-module')) {
   356→      throw new ERR_REQUIRE_ESM(url, true);
   357→    }
   358→    const resolvedImportAttributes = resolveResult.importAttributes ?? importAttributes;
   359→    let job = this.loadCache.get(url, resolvedImportAttributes.type);
   360→    if (job !== undefined) {
   361→      // This module is being evaluated, which means it's imported in a previous link
   362→      // in a cycle.
   363→      if (job.module.getStatus() === kEvaluating) {
   364→        const parentFilename = urlToFilename(parentURL);
   365→        let message = `Cannot import Module ${specifier} in a cycle.`;
   366→        if (parentFilename) {
   367→          message += ` (from ${parentFilename})`;
   368→        }
   369→        throw new ERR_REQUIRE_CYCLE_MODULE(message);
   370→      }
   371→      // Otherwise the module could be imported before but the evaluation may be already
   372→      // completed (e.g. the require call is lazy) so it's okay. We will return the
   373→      // module now and check asynchronicity of the entire graph later, after the
   374→      // graph is instantiated.
   375→      return job;
   376→    }
   377→
   378→    defaultLoadSync ??= require('internal/modules/esm/load').defaultLoadSync;
   379→    const loadResult = defaultLoadSync(url, { format, importAttributes });
   380→
   381→    // Use the synchronous commonjs translator which can deal with cycles.
   382→    const finalFormat = loadResult.format === 'commonjs' ? 'commonjs-sync' : loadResult.format;
   383→
   384→    if (finalFormat === 'wasm') {
   385→      assert.fail('WASM is currently unsupported by require(esm)');
   386→    }
   387→
   388→    const { source } = loadResult;
   389→    const isMain = (parentURL === undefined);
   390→    const wrap = this.#translate(url, finalFormat, source, isMain);
   391→    assert(wrap instanceof ModuleWrap, `Translator used for require(${url}) should not be async`);
   392→
   393→    if (process.env.WATCH_REPORT_DEPENDENCIES && process.send) {
   394→      process.send({ 'watch:import': [url] });
   395→    }
   396→
   397→    const cjsModule = wrap[imported_cjs_symbol];
   398→    if (cjsModule) {
   399→      assert(finalFormat === 'commonjs-sync');
   400→      // Check if the ESM initiating import CJS is being required by the same CJS module.
   401→      if (cjsModule?.[kIsExecuting]) {
   402→        const parentFilename = urlToFilename(parentURL);
   403→        let message = `Cannot import CommonJS Module ${specifier} in a cycle.`;
   404→        if (parentFilename) {
   405→          message += ` (from ${parentFilename})`;
   406→        }
   407→        throw new ERR_REQUIRE_CYCLE_MODULE(message);
   408→      }
   409→    }
   410→
   411→    const inspectBrk = (isMain && getOptionValue('--inspect-brk'));
   412→    const { ModuleJobSync } = require('internal/modules/esm/module_job');
   413→    job = new ModuleJobSync(this, url, importAttributes, wrap, isMain, inspectBrk);
   414→
   415→    this.loadCache.set(url, importAttributes.type, job);
   416→    return job;
   417→  }
   418→
   419→  /**
   420→   * Translate a loaded module source into a ModuleWrap. This is run synchronously,
   421→   * but the translator may return the ModuleWrap in a Promise.
   422→   * @param {string} url URL of the module to be translated.
   423→   * @param {string} format Format of the module to be translated. This is used to find
   424→   *                        matching translators.
   425→   * @param {ModuleSource} source Source of the module to be translated.
   426→   * @param {boolean} isMain Whether the module to be translated is the entry point.
   427→   * @returns {ModuleWrap | Promise<ModuleWrap>}
   428→   */
