   177→   *   allowImportMetaResolve: boolean;
   178→   *   load(url: string, context: object): Promise<LoadResult>
   179→   *   resolve(
   180→   *     originalSpecifier:
   181→   *     string, parentURL: string,
   182→   *     importAttributes: Record<string, string>
   183→   *   ): Promise<ResolveResult>
   184→   *   resolveSync(
   185→   *     originalSpecifier:
   186→   *     string, parentURL: string,
   187→   *     importAttributes: Record<string, string>
   188→   *   ) ResolveResult;
   189→   *   register(specifier: string, parentURL: string): any;
   190→   *   forceLoadHooks(): void;
   191→   * }
   192→   * ```
   193→   *
   194→   * Note that this class _also_ implements the `Customizations`
   195→   * interface, as does `CustomizedModuleLoader` and `Hooks`.
   196→   *
   197→   * Calling this function alters how modules are loaded and should be
   198→   * invoked with care.
   199→   * @param {object} customizations
   200→   */
   201→  setCustomizations(customizations) {
   202→    this.#customizations = customizations;
   203→    if (customizations) {
   204→      this.allowImportMetaResolve = customizations.allowImportMetaResolve;
   205→    } else {
   206→      this.allowImportMetaResolve = true;
   207→    }
   208→  }
   209→
   210→  async eval(source, url, isEntryPoint = false) {
   211→    const { ModuleJob } = require('internal/modules/esm/module_job');
   212→    const wrap = compileSourceTextModule(url, source, this);
   213→    const module = await onImport.tracePromise(async () => {
   214→      const job = new ModuleJob(
   215→        this, url, undefined, wrap, false, false);
   216→      this.loadCache.set(url, undefined, job);
   217→      const { module } = await job.run(isEntryPoint);
   218→      return module;
   219→    }, {
   220→      __proto__: null,
   221→      parentURL: '<eval>',
   222→      url,
   223→    });
   224→
   225→    return {
   226→      __proto__: null,
   227→      namespace: module.getNamespace(),
   228→      module,
   229→    };
   230→  }
   231→
   232→  /**
   233→   * Get a (possibly not yet fully linked) module job from the cache, or create one and return its Promise.
   234→   * @param {string} specifier The module request of the module to be resolved. Typically, what's
   235→   *                           requested by `import '<specifier>'` or `import('<specifier>')`.
   236→   * @param {string} [parentURL] The URL of the module where the module request is initiated.
   237→   *                             It's undefined if it's from the root module.
   238→   * @param {ImportAttributes} importAttributes Attributes from the import statement or expression.
   239→   * @returns {Promise<ModuleJobBase}
   240→   */
   241→  async getModuleJobForImport(specifier, parentURL, importAttributes) {
   242→    const resolveResult = await this.resolve(specifier, parentURL, importAttributes);
   243→    return this.#getJobFromResolveResult(resolveResult, parentURL, importAttributes, false);
   244→  }
   245→
   246→  /**
   247→   * Similar to {@link getModuleJobForImport} but it's used for `require()` resolved by the ESM loader
   248→   * in imported CJS modules. This runs synchronously and when it returns, the module job's module
   249→   * requests are all linked.
   250→   * @param {string} specifier See {@link getModuleJobForImport}
   251→   * @param {string} [parentURL] See {@link getModuleJobForImport}
   252→   * @param {ImportAttributes} importAttributes See {@link getModuleJobForImport}
   253→   * @returns {Promise<ModuleJobBase}
   254→   */
   255→  getModuleJobForRequireInImportedCJS(specifier, parentURL, importAttributes) {
   256→    const resolveResult = this.resolveSync(specifier, parentURL, importAttributes);
   257→    return this.#getJobFromResolveResult(resolveResult, parentURL, importAttributes, true);
   258→  }
   259→
   260→  /**
   261→   * Given a resolved module request, obtain a ModuleJobBase from it - if it's already cached,
   262→   * return the cached ModuleJobBase. Otherwise, load its source and translate it into a ModuleWrap first.
   263→   * @param {{ format: string, url: string }} resolveResult Resolved module request.
   264→   * @param {string} [parentURL] See {@link getModuleJobForImport}
   265→   * @param {ImportAttributes} importAttributes See {@link getModuleJobForImport}
   266→   * @param {boolean} isForRequireInImportedCJS Whether this is done for require() in imported CJS.
   267→   * @returns {ModuleJobBase}
   268→   */
   269→  #getJobFromResolveResult(resolveResult, parentURL, importAttributes, isForRequireInImportedCJS = false) {
   270→    const { url, format } = resolveResult;
   271→    const resolvedImportAttributes = resolveResult.importAttributes ?? importAttributes;
   272→    let job = this.loadCache.get(url, resolvedImportAttributes.type);
   273→
   274→    if (job === undefined) {
   275→      job = this.#createModuleJob(url, resolvedImportAttributes, parentURL, format, isForRequireInImportedCJS);
   276→    }
   277→
   278→    return job;
   279→  }
   280→
   281→  /**
   282→   * This constructs (creates, instantiates and evaluates) a module graph that
   283→   * is require()'d.
   284→   * @param {CJSModule} mod CJS module wrapper of the ESM.
   285→   * @param {string} filename Resolved filename of the module being require()'d
   286→   * @param {string} source Source code. TODO(joyeecheung): pass the raw buffer.
   287→   * @param {string} isMain Whether this module is a main module.
   288→   * @param {CJSModule|undefined} parent Parent module, if any.
   289→   * @returns {{wrap: ModuleWrap, namespace: ModuleNamespaceObject}}
   290→   */
   291→  importSyncForRequire(mod, filename, source, isMain, parent) {
   292→    const url = pathToFileURL(filename).href;
   293→    let job = this.loadCache.get(url, kImplicitTypeAttribute);
   294→    // This module job is already created:
   295→    // 1. If it was loaded by `require()` before, at this point the instantiation
   296→    //    is already completed and we can check the whether it is in a cycle
   297→    //    (in that case the module status is kEvaluaing), and whether the
   298→    //    required graph is synchronous.
   299→    // 2. If it was loaded by `import` before, only allow it if it's already evaluated
   300→    //    to forbid cycles.
   301→    //    TODO(joyeecheung): ensure that imported synchronous graphs are evaluated
   302→    //    synchronously so that any previously imported synchronous graph is already
   303→    //    evaluated at this point.
   304→    if (job !== undefined) {
   305→      mod[kRequiredModuleSymbol] = job.module;
   306→      if (job.module.async) {
   307→        throw new ERR_REQUIRE_ASYNC_MODULE();
   308→      }
   309→      if (job.module.getStatus() !== kEvaluated) {
   310→        const parentFilename = urlToFilename(parent?.filename);
   311→        let message = `Cannot require() ES Module ${filename} in a cycle.`;
   312→        if (parentFilename) {
   313→          message += ` (from ${parentFilename})`;
   314→        }
   315→        throw new ERR_REQUIRE_CYCLE_MODULE(message);
   316→      }
   317→      return { wrap: job.module, namespace: job.module.getNamespaceSync() };
   318→    }
   319→    // TODO(joyeecheung): refactor this so that we pre-parse in C++ and hit the
   320→    // cache here, or use a carrier object to carry the compiled module script
   321→    // into the constructor to ensure cache hit.
   322→    const wrap = compileSourceTextModule(url, source, this);
   323→    const inspectBrk = (isMain && getOptionValue('--inspect-brk'));
   324→
   325→    const { ModuleJobSync } = require('internal/modules/esm/module_job');
   326→    job = new ModuleJobSync(this, url, kEmptyObject, wrap, isMain, inspectBrk);
   327→    this.loadCache.set(url, kImplicitTypeAttribute, job);
   328→    mod[kRequiredModuleSymbol] = job.module;
   329→    return { wrap: job.module, namespace: job.runSync().namespace };
   330→  }
   331→
   332→  /**
   333→   * Resolve individual module requests and create or get the cached ModuleWraps for
   334→   * each of them. This is only used to create a module graph being require()'d.
   335→   * @param {string} specifier Specifier of the the imported module.
   336→   * @param {string} parentURL Where the import comes from.
   337→   * @param {object} importAttributes import attributes from the import statement.
   338→   * @returns {ModuleJobBase}
   339→   */
   340→  getModuleJobForRequire(specifier, parentURL, importAttributes) {
   341→    const parsed = URLParse(specifier);
   342→    if (parsed != null) {
   343→      const protocol = parsed.protocol;
   344→      if (protocol === 'https:' || protocol === 'http:') {
   345→        throw new ERR_NETWORK_IMPORT_DISALLOWED(specifier, parentURL,
   346→                                                'ES modules cannot be loaded by require() from the network');
   347→      }
   348→      assert(protocol === 'file:' || protocol === 'node:' || protocol === 'data:');
   349→    }
   350→
   351→    // TODO(joyeecheung): consolidate cache behavior and use resolveSync() and
   352→    // loadSync() here.
   353→    const resolveResult = this.#cachedDefaultResolve(specifier, parentURL, importAttributes);
   354→    const { url, format } = resolveResult;
   355→    if (!getOptionValue('--experimental-require-module')) {
   356→      throw new ERR_REQUIRE_ESM(url, true);
   357→    }
   358→    const resolvedImportAttributes = resolveResult.importAttributes ?? importAttributes;
   359→    let job = this.loadCache.get(url, resolvedImportAttributes.type);
   360→    if (job !== undefined) {
   361→      // This module is being evaluated, which means it's imported in a previous link
   362→      // in a cycle.
   363→      if (job.module.getStatus() === kEvaluating) {
   364→        const parentFilename = urlToFilename(parentURL);
   365→        let message = `Cannot import Module ${specifier} in a cycle.`;
   366→        if (parentFilename) {
   367→          message += ` (from ${parentFilename})`;
   368→        }
   369→        throw new ERR_REQUIRE_CYCLE_MODULE(message);
   370→      }
   371→      // Otherwise the module could be imported before but the evaluation may be already
   372→      // completed (e.g. the require call is lazy) so it's okay. We will return the
   373→      // module now and check asynchronicity of the entire graph later, after the
   374→      // graph is instantiated.
   375→      return job;
   376→    }
   377→
   378→    defaultLoadSync ??= require('internal/modules/esm/load').defaultLoadSync;
   379→    const loadResult = defaultLoadSync(url, { format, importAttributes });
   380→
   381→    // Use the synchronous commonjs translator which can deal with cycles.
   382→    const finalFormat = loadResult.format === 'commonjs' ? 'commonjs-sync' : loadResult.format;
   383→
   384→    if (finalFormat === 'wasm') {
   385→      assert.fail('WASM is currently unsupported by require(esm)');
   386→    }
   387→
   388→    const { source } = loadResult;
   389→    const isMain = (parentURL === undefined);
   390→    const wrap = this.#translate(url, finalFormat, source, isMain);
   391→    assert(wrap instanceof ModuleWrap, `Translator used for require(${url}) should not be async`);
   392→
   393→    if (process.env.WATCH_REPORT_DEPENDENCIES && process.send) {
   394→      process.send({ 'watch:import': [url] });
   395→    }
   396→
   397→    const cjsModule = wrap[imported_cjs_symbol];
   398→    if (cjsModule) {
   399→      assert(finalFormat === 'commonjs-sync');
   400→      // Check if the ESM initiating import CJS is being required by the same CJS module.
   401→      if (cjsModule?.[kIsExecuting]) {
   402→        const parentFilename = urlToFilename(parentURL);
   403→        let message = `Cannot import CommonJS Module ${specifier} in a cycle.`;
   404→        if (parentFilename) {
   405→          message += ` (from ${parentFilename})`;
   406→        }
   407→        throw new ERR_REQUIRE_CYCLE_MODULE(message);
   408→      }
   409→    }
   410→
   411→    const inspectBrk = (isMain && getOptionValue('--inspect-brk'));
   412→    const { ModuleJobSync } = require('internal/modules/esm/module_job');
   413→    job = new ModuleJobSync(this, url, importAttributes, wrap, isMain, inspectBrk);
   414→
   415→    this.loadCache.set(url, importAttributes.type, job);
   416→    return job;
   417→  }
   418→
   419→  /**
   420→   * Translate a loaded module source into a ModuleWrap. This is run synchronously,
   421→   * but the translator may return the ModuleWrap in a Promise.
   422→   * @param {string} url URL of the module to be translated.
   423→   * @param {string} format Format of the module to be translated. This is used to find
   424→   *                        matching translators.
   425→   * @param {ModuleSource} source Source of the module to be translated.
   426→   * @param {boolean} isMain Whether the module to be translated is the entry point.
   427→   * @returns {ModuleWrap | Promise<ModuleWrap>}
   428→   */
   429→  #translate(url, format, source, isMain) {
   430→    this.validateLoadResult(url, format);
   431→    const translator = getTranslators().get(format);
   432→
   433→    if (!translator) {
   434→      throw new ERR_UNKNOWN_MODULE_FORMAT(format, url);
   435→    }
   436→
   437→    return FunctionPrototypeCall(translator, this, url, source, isMain);
   438→  }
   439→
   440→  /**
   441→   * Load a module and translate it into a ModuleWrap for require() in imported CJS.
   442→   * This is run synchronously, and the translator always return a ModuleWrap synchronously.
   443→   * @param {string} url URL of the module to be translated.
   444→   * @param {object} loadContext See {@link load}
   445→   * @param {boolean} isMain Whether the module to be translated is the entry point.
   446→   * @returns {ModuleWrap}
   447→   */
   448→  loadAndTranslateForRequireInImportedCJS(url, loadContext, isMain) {
   449→    const { format: formatFromLoad, source } = this.#loadSync(url, loadContext);
   450→
   451→    if (formatFromLoad === 'wasm') {  // require(wasm) is not supported.
   452→      throw new ERR_UNKNOWN_MODULE_FORMAT(formatFromLoad, url);
   453→    }
   454→
   455→    if (formatFromLoad === 'module' || formatFromLoad === 'module-typescript') {
   456→      if (!getOptionValue('--experimental-require-module')) {
   457→        throw new ERR_REQUIRE_ESM(url, true);
   458→      }
   459→    }
   460→
   461→    let finalFormat = formatFromLoad;
   462→    if (formatFromLoad === 'commonjs') {
   463→      finalFormat = 'require-commonjs';
   464→    }
   465→    if (formatFromLoad === 'commonjs-typescript') {
   466→      finalFormat = 'require-commonjs-typescript';
   467→    }
   468→
   469→    const wrap = this.#translate(url, finalFormat, source, isMain);
   470→    assert(wrap instanceof ModuleWrap, `Translator used for require(${url}) should not be async`);
   471→    return wrap;
   472→  }
   473→
   474→  /**
   475→   * Load a module and translate it into a ModuleWrap for ordinary imported ESM.
   476→   * This is run asynchronously.
   477→   * @param {string} url URL of the module to be translated.
   478→   * @param {object} loadContext See {@link load}
   479→   * @param {boolean} isMain Whether the module to be translated is the entry point.
   480→   * @returns {Promise<ModuleWrap>}
   481→   */
   482→  async loadAndTranslate(url, loadContext, isMain) {
   483→    const { format, source } = await this.load(url, loadContext);
   484→    return this.#translate(url, format, source, isMain);
   485→  }
   486→
   487→  /**
   488→   * Load a module and translate it into a ModuleWrap, and create a ModuleJob from it.
   489→   * This runs synchronously. If isForRequireInImportedCJS is true, the module should be linked
   490→   * by the time this returns. Otherwise it may still have pending module requests.
   491→   * @param {string} url The URL that was resolved for this module.
   492→   * @param {ImportAttributes} importAttributes See {@link getModuleJobForImport}
   493→   * @param {string} [parentURL] See {@link getModuleJobForImport}
   494→   * @param {string} [format] The format hint possibly returned by the `resolve` hook
   495→   * @param {boolean} isForRequireInImportedCJS Whether this module job is created for require()
   496→   *                                            in imported CJS.
   497→   * @returns {ModuleJobBase} The (possibly pending) module job
   498→   */
   499→  #createModuleJob(url, importAttributes, parentURL, format, isForRequireInImportedCJS) {
   500→    const context = { format, importAttributes };
   501→
   502→    const isMain = parentURL === undefined;
   503→    let moduleOrModulePromise;
   504→    if (isForRequireInImportedCJS) {
   505→      moduleOrModulePromise = this.loadAndTranslateForRequireInImportedCJS(url, context, isMain);
   506→    } else {
   507→      moduleOrModulePromise = this.loadAndTranslate(url, context, isMain);
   508→    }
   509→
   510→    const inspectBrk = (
   511→      isMain &&
   512→      getOptionValue('--inspect-brk')
   513→    );
   514→
   515→    if (process.env.WATCH_REPORT_DEPENDENCIES && process.send) {
   516→      process.send({ 'watch:import': [url] });
   517→    }
   518→
   519→    const { ModuleJob } = require('internal/modules/esm/module_job');
   520→    const job = new ModuleJob(
   521→      this,
   522→      url,
   523→      importAttributes,
   524→      moduleOrModulePromise,
   525→      isMain,
   526→      inspectBrk,
   527→      isForRequireInImportedCJS,
   528→    );
   529→
   530→    this.loadCache.set(url, importAttributes.type, job);
   531→
   532→    return job;
   533→  }
   534→
   535→  /**
   536→   * This method is usually called indirectly as part of the loading processes.
   537→   * Use directly with caution.
   538→   * @param {string} specifier The first parameter of an `import()` expression.
   539→   * @param {string} parentURL Path of the parent importing the module.
   540→   * @param {Record<string, string>} importAttributes Validations for the
   541→   *                                                  module import.
   542→   * @returns {Promise<ModuleExports>}
   543→   */
   544→  async import(specifier, parentURL, importAttributes, isEntryPoint = false) {
   545→    return onImport.tracePromise(async () => {
   546→      const moduleJob = await this.getModuleJobForImport(specifier, parentURL, importAttributes);
   547→      const { module } = await moduleJob.run(isEntryPoint);
   548→      return module.getNamespace();
   549→    }, {
   550→      __proto__: null,
   551→      parentURL,
   552→      url: specifier,
   553→    });
   554→  }
   555→
   556→  /**
   557→   * @see {@link CustomizedModuleLoader.register}
   558→   */
   559→  register(specifier, parentURL, data, transferList, isInternal) {
   560→    if (!this.#customizations) {
   561→      // `CustomizedModuleLoader` is defined at the bottom of this file and
   562→      // available well before this line is ever invoked. This is here in
   563→      // order to preserve the git diff instead of moving the class.
   564→      // eslint-disable-next-line no-use-before-define
   565→      this.setCustomizations(new CustomizedModuleLoader());
   566→    }
   567→    return this.#customizations.register(`${specifier}`, `${parentURL}`, data, transferList, isInternal);
   568→  }
   569→
   570→  /**
   571→   * Resolve a module request to a URL identifying the location of the module. Handles customization hooks,
   572→   * if any.
   573→   * @param {string|URL} specifier The module request of the module to be resolved. Typically, what's
   574→   *                               requested by `import specifier`, `import(specifier)` or
   575→   *                               `import.meta.resolve(specifier)`.
   576→   * @param {string} [parentURL] The URL of the module where the module request is initiated.
   577→   *                             It's undefined if it's from the root module.
   578→   * @param {ImportAttributes} importAttributes Attributes from the import statement or expression.
   579→   * @returns {Promise<{format: string, url: string}>}
   580→   */
   581→  resolve(specifier, parentURL, importAttributes) {
   582→    specifier = `${specifier}`;
   583→    if (this.#customizations) {  // Only has module.register hooks.
   584→      return this.#customizations.resolve(specifier, parentURL, importAttributes);
   585→    }
   586→    return this.#cachedDefaultResolve(specifier, parentURL, importAttributes);
   587→  }
   588→
   589→  /**
   590→   * Either return a cached resolution, or perform the default resolution which is synchronous, and
   591→   * cache the result.
   592→   * @param {string} specifier See {@link resolve}.
   593→   * @param {string} [parentURL] See {@link resolve}.
   594→   * @param {ImportAttributes} importAttributes See {@link resolve}.
   595→   * @returns {{ format: string, url: string }}
   596→   */
   597→  #cachedDefaultResolve(specifier, parentURL, importAttributes) {
   598→    const requestKey = this.#resolveCache.serializeKey(specifier, importAttributes);
   599→    const cachedResult = this.#resolveCache.get(requestKey, parentURL);
   600→    if (cachedResult != null) {
   601→      return cachedResult;
   602→    }
   603→    const result = this.defaultResolve(specifier, parentURL, importAttributes);
   604→    this.#resolveCache.set(requestKey, parentURL, result);
   605→    return result;
   606→  }
   607→
   608→  /**
   609→   * This is the default resolve step for future synchronous hooks, which incorporates asynchronous hooks
   610→   * from module.register() which are run in a blocking fashion for it to be synchronous.
   611→   * @param {string|URL} specifier See {@link resolveSync}.
   612→   * @param {{ parentURL?: string, importAttributes: ImportAttributes}} context See {@link resolveSync}.
   613→   * @returns {{ format: string, url: string }}
   614→   */
   615→  #resolveAndMaybeBlockOnLoaderThread(specifier, context) {
   616→    if (this.#customizations) {
   617→      return this.#customizations.resolveSync(specifier, context.parentURL, context.importAttributes);
   618→    }
   619→    return this.#cachedDefaultResolve(specifier, context.parentURL, context.importAttributes);
   620→  }
   621→
   622→  /**
   623→   * Similar to {@link resolve}, but the results are always synchronously returned. If there are any
   624→   * asynchronous resolve hooks from module.register(), it will block until the results are returned
   625→   * from the loader thread for this to be synchornous.
   626→   * This is here to support `import.meta.resolve()`, `require()` in imported CJS, and
   627→   * future synchronous hooks.
   628→   *
   629→   * TODO(joyeecheung): consolidate the cache behavior and use this in require(esm).
   630→   * @param {string|URL} specifier See {@link resolve}.
   631→   * @param {string} [parentURL] See {@link resolve}.
   632→   * @param {ImportAttributes} [importAttributes] See {@link resolve}.
   633→   * @returns {{ format: string, url: string }}
   634→   */
   635→  resolveSync(specifier, parentURL, importAttributes = { __proto__: null }) {
   636→    return this.#resolveAndMaybeBlockOnLoaderThread(`${specifier}`, { parentURL, importAttributes });
   637→  }
   638→
   639→  /**
   640→   * Our `defaultResolve` is synchronous and can be used in both
   641→   * `resolve` and `resolveSync`. This function is here just to avoid
   642→   * repeating the same code block twice in those functions.
   643→   */
   644→  defaultResolve(originalSpecifier, parentURL, importAttributes) {
   645→    defaultResolve ??= require('internal/modules/esm/resolve').defaultResolve;
   646→
   647→    const context = {
   648→      __proto__: null,
   649→      conditions: this.#defaultConditions,
   650→      importAttributes,
   651→      parentURL,
   652→    };
   653→
   654→    return defaultResolve(originalSpecifier, context);
   655→  }
   656→
   657→  /**
   658→   * Provide source that is understood by one of Node's translators. Handles customization hooks,
   659→   * if any.
   660→   * @param {string} url The URL of the module to be loaded.
   661→   * @param {object} context Metadata about the module
   662→   * @returns {Promise<{ format: ModuleFormat, source: ModuleSource }>}
   663→   */
   664→  async load(url, context) {
   665→    if (this.#customizations) {
   666→      return this.#customizations.load(url, context);
   667→    }
   668→
   669→    defaultLoad ??= require('internal/modules/esm/load').defaultLoad;
   670→    return defaultLoad(url, context);
   671→  }
   672→
   673→  /**
   674→   * This is the default load step for future synchronous hooks, which incorporates asynchronous hooks
   675→   * from module.register() which are run in a blocking fashion for it to be synchronous.
   676→   * @param {string} url See {@link load}
   677→   * @param {object} context See {@link load}
   678→   * @returns {{ format: ModuleFormat, source: ModuleSource }}
   679→   */
   680→  #loadAndMaybeBlockOnLoaderThread(url, context) {
   681→    if (this.#customizations) {
   682→      return this.#customizations.loadSync(url, context);
   683→    }
   684→    defaultLoadSync ??= require('internal/modules/esm/load').defaultLoadSync;
   685→    return defaultLoadSync(url, context);
   686→  }
   687→
   688→  /**
   689→   * Similar to {@link load} but this is always run synchronously. If there are asynchronous hooks
   690→   * from module.register(), this blocks on the loader thread for it to return synchronously.
   691→   *
   692→   * This is here to support `require()` in imported CJS and future synchronous hooks.
   693→   *
   694→   * TODO(joyeecheung): consolidate the cache behavior and use this in require(esm).
   695→   * @param {string} url See {@link load}
   696→   * @param {object} [context] See {@link load}
   697→   * @returns {{ format: ModuleFormat, source: ModuleSource }}
   698→   */
   699→  #loadSync(url, context) {
   700→    return this.#loadAndMaybeBlockOnLoaderThread(url, context);
   701→  }
   702→
   703→  validateLoadResult(url, format) {
   704→    if (format == null) {
   705→      require('internal/modules/esm/load').throwUnknownModuleFormat(url, format);
   706→    }
   707→  }
   708→
   709→  importMetaInitialize(meta, context) {
   710→    if (this.#customizations) {
   711→      return this.#customizations.importMetaInitialize(meta, context, this);
   712→    }
   713→    importMetaInitializer ??= require('internal/modules/esm/initialize_import_meta').initializeImportMeta;
   714→    meta = importMetaInitializer(meta, context, this);
   715→    return meta;
   716→  }
   717→
   718→  /**
   719→   * No-op when no hooks have been supplied.
   720→   */
   721→  forceLoadHooks() {
   722→    this.#customizations?.forceLoadHooks();
   723→  }
   724→}
   725→ObjectSetPrototypeOf(ModuleLoader.prototype, null);
   726→
   727→class CustomizedModuleLoader {
   728→
   729→  allowImportMetaResolve = true;
   730→
   731→  /**
   732→   * Instantiate a module loader that uses user-provided custom loader hooks.
   733→   */
   734→  constructor() {
   735→    getHooksProxy();
   736→  }
   737→
   738→  /**
   739→   * Register some loader specifier.
   740→   * @param {string} originalSpecifier The specified URL path of the loader to
   741→   *                                   be registered.
   742→   * @param {string} parentURL The parent URL from where the loader will be
   743→   *                           registered if using it package name as specifier
   744→   * @param {any} [data] Arbitrary data to be passed from the custom loader
   745→   * (user-land) to the worker.
   746→   * @param {any[]} [transferList] Objects in `data` that are changing ownership
   747→   * @param {boolean} [isInternal] For internal loaders that should not be publicly exposed.
   748→   * @returns {{ format: string, url: URL['href'] }}
   749→   */
   750→  register(originalSpecifier, parentURL, data, transferList, isInternal) {
   751→    return hooksProxy.makeSyncRequest('register', transferList, originalSpecifier, parentURL, data, isInternal);
   752→  }
   753→
   754→  /**
   755→   * Resolve the location of the module.
   756→   * @param {string} originalSpecifier The specified URL path of the module to
   757→   *                                   be resolved.
   758→   * @param {string} [parentURL] The URL path of the module's parent.
   759→   * @param {ImportAttributes} importAttributes Attributes from the import
   760→   *                                            statement or expression.
   761→   * @returns {{ format: string, url: URL['href'] }}
   762→   */
   763→  resolve(originalSpecifier, parentURL, importAttributes) {
   764→    return hooksProxy.makeAsyncRequest('resolve', undefined, originalSpecifier, parentURL, importAttributes);
   765→  }
   766→
   767→  resolveSync(originalSpecifier, parentURL, importAttributes) {
   768→    // This happens only as a result of `import.meta.resolve` calls, which must be sync per spec.
   769→    return hooksProxy.makeSyncRequest('resolve', undefined, originalSpecifier, parentURL, importAttributes);
   770→  }
   771→
   772→  /**
   773→   * Provide source that is understood by one of Node's translators.
   774→   * @param {URL['href']} url The URL/path of the module to be loaded
   775→   * @param {object} [context] Metadata about the module
   776→   * @returns {Promise<{ format: ModuleFormat, source: ModuleSource }>}
   777→   */
   778→  load(url, context) {
   779→    return hooksProxy.makeAsyncRequest('load', undefined, url, context);
   780→  }
   781→  loadSync(url, context) {
   782→    return hooksProxy.makeSyncRequest('load', undefined, url, context);
   783→  }
   784→
   785→  importMetaInitialize(meta, context, loader) {
   786→    hooksProxy.importMetaInitialize(meta, context, loader);
   787→  }
   788→
   789→  forceLoadHooks() {
   790→    hooksProxy.waitForWorker();
   791→  }
   792→}
   793→
   794→let emittedLoaderFlagWarning = false;
   795→/**
   796→ * A loader instance is used as the main entry point for loading ES modules. Currently, this is a singleton; there is
   797→ * only one used for loading the main module and everything in its dependency graph, though separate instances of this
   798→ * class might be instantiated as part of bootstrap for other purposes.
   799→ * @returns {ModuleLoader}
   800→ */
   801→function createModuleLoader() {
   802→  let customizations = null;
   803→  // Don't spawn a new worker if custom loaders are disabled. For instance, if
   804→  // we're already in a worker thread created by instantiating
   805→  // CustomizedModuleLoader; doing so would cause an infinite loop.
   806→  if (!forceDefaultLoader()) {
   807→    const userLoaderPaths = getOptionValue('--experimental-loader');
   808→    if (userLoaderPaths.length > 0) {
   809→      if (!emittedLoaderFlagWarning) {
   810→        const readableURIEncode = (string) => ArrayPrototypeReduce(
   811→          [
   812→            [/'/g, '%27'], // We need to URL-encode the single quote as it's the delimiter for the --import flag.
   813→            [/%22/g, '"'], // We can decode the double quotes to improve readability.
   814→            [/%2F/ig, '/'], // We can decode the slashes to improve readability.
   815→          ],
   816→          (str, { 0: regex, 1: replacement }) => RegExpPrototypeSymbolReplace(hardenRegExp(regex), str, replacement),
   817→          encodeURIComponent(string));
   818→        process.emitWarning(
   819→          '`--experimental-loader` may be removed in the future; instead use `register()`:\n' +
   820→          `--import 'data:text/javascript,import { register } from "node:module"; import { pathToFileURL } from "node:url"; ${ArrayPrototypeJoin(
   821→            ArrayPrototypeMap(userLoaderPaths, (loader) => `register(${readableURIEncode(JSONStringify(loader))}, pathToFileURL("./"))`),
   822→            '; ',
   823→          )};'`,
   824→          'ExperimentalWarning',
   825→        );
   826→        emittedLoaderFlagWarning = true;
   827→      }
   828→      customizations = new CustomizedModuleLoader();
   829→    }
   830→  }
   831→
   832→  return new ModuleLoader(customizations);
   833→}
   834→
   835→
   836→/**
   837→ * Get the HooksProxy instance. If it is not defined, then create a new one.
   838→ * @returns {HooksProxy}
   839→ */
   840→function getHooksProxy() {
   841→  if (!hooksProxy) {
   842→    const { HooksProxy } = require('internal/modules/esm/hooks');
   843→    hooksProxy = new HooksProxy();
   844→  }
   845→
   846→  return hooksProxy;
   847→}
   848→
   849→let cascadedLoader;
   850→
   851→/**
   852→ * This is a singleton ESM loader that integrates the loader hooks, if any.
   853→ * It it used by other internal built-ins when they need to load ESM code
   854→ * while also respecting hooks.
   855→ * When built-ins need access to this loader, they should do
   856→ * require('internal/module/esm/loader').getOrInitializeCascadedLoader()
   857→ * lazily only right before the loader is actually needed, and don't do it
   858→ * in the top-level, to avoid circular dependencies.
   859→ * @returns {ModuleLoader}
   860→ */
   861→function getOrInitializeCascadedLoader() {
   862→  cascadedLoader ??= createModuleLoader();
   863→  return cascadedLoader;
   864→}
   865→
   866→/**
   867→ * Register a single loader programmatically.
   868→ * @param {string|URL} specifier
   869→ * @param {string|URL} [parentURL] Base to use when resolving `specifier`; optional if
   870→ * `specifier` is absolute. Same as `options.parentUrl`, just inline
   871→ * @param {object} [options] Additional options to apply, described below.
   872→ * @param {string|URL} [options.parentURL] Base to use when resolving `specifier`
   873→ * @param {any} [options.data] Arbitrary data passed to the loader's `initialize` hook
   874→ * @param {any[]} [options.transferList] Objects in `data` that are changing ownership
   875→ * @returns {void} We want to reserve the return value for potential future extension of the API.
   876→ * @example
   877→ * ```js
   878→ * register('./myLoader.js');
   879→ * register('ts-node/esm', { parentURL: import.meta.url });
   880→ * register('./myLoader.js', { parentURL: import.meta.url });
   881→ * register('ts-node/esm', import.meta.url);
   882→ * register('./myLoader.js', import.meta.url);
   883→ * register(new URL('./myLoader.js', import.meta.url));
   884→ * register('./myLoader.js', {
   885→ *   parentURL: import.meta.url,
   886→ *   data: { banana: 'tasty' },
   887→ * });
   888→ * register('./myLoader.js', {
   889→ *   parentURL: import.meta.url,
   890→ *   data: someArrayBuffer,
   891→ *   transferList: [someArrayBuffer],
   892→ * });
   893→ * ```
   894→ */
   895→function register(specifier, parentURL = undefined, options) {
   896→  if (parentURL != null && typeof parentURL === 'object' && !isURL(parentURL)) {
   897→    options = parentURL;
   898→    parentURL = options.parentURL;
   899→  }
   900→  getOrInitializeCascadedLoader().register(
   901→    specifier,
   902→    parentURL ?? 'data:',
   903→    options?.data,
   904→    options?.transferList,
   905→  );
   906→}
   907→
   908→module.exports = {
   909→  createModuleLoader,
   910→  getHooksProxy,
   911→  getOrInitializeCascadedLoader,
   912→  register,
   913→};
