   556→  /**
   557→   * @see {@link CustomizedModuleLoader.register}
   558→   */
   559→  register(specifier, parentURL, data, transferList, isInternal) {
   560→    if (!this.#customizations) {
   561→      // `CustomizedModuleLoader` is defined at the bottom of this file and
   562→      // available well before this line is ever invoked. This is here in
   563→      // order to preserve the git diff instead of moving the class.
   564→      // eslint-disable-next-line no-use-before-define
   565→      this.setCustomizations(new CustomizedModuleLoader());
   566→    }
   567→    return this.#customizations.register(`${specifier}`, `${parentURL}`, data, transferList, isInternal);
   568→  }
