   570→  /**
   571→   * Resolve a module request to a URL identifying the location of the module. Handles customization hooks,
   572→   * if any.
   573→   * @param {string|URL} specifier The module request of the module to be resolved. Typically, what's
   574→   *                               requested by `import specifier`, `import(specifier)` or
   575→   *                               `import.meta.resolve(specifier)`.
   576→   * @param {string} [parentURL] The URL of the module where the module request is initiated.
   577→   *                             It's undefined if it's from the root module.
   578→   * @param {ImportAttributes} importAttributes Attributes from the import statement or expression.
   579→   * @returns {Promise<{format: string, url: string}>}
   580→   */
   581→  resolve(specifier, parentURL, importAttributes) {
   582→    specifier = `${specifier}`;
   583→    if (this.#customizations) {  // Only has module.register hooks.
   584→      return this.#customizations.resolve(specifier, parentURL, importAttributes);
   585→    }
   586→    return this.#cachedDefaultResolve(specifier, parentURL, importAttributes);
   587→  }
   588→
   589→  /**
   590→   * Either return a cached resolution, or perform the default resolution which is synchronous, and
   591→   * cache the result.
   592→   * @param {string} specifier See {@link resolve}.
   593→   * @param {string} [parentURL] See {@link resolve}.
   594→   * @param {ImportAttributes} importAttributes See {@link resolve}.
   595→   * @returns {{ format: string, url: string }}
   596→   */
   597→  #cachedDefaultResolve(specifier, parentURL, importAttributes) {
   598→    const requestKey = this.#resolveCache.serializeKey(specifier, importAttributes);
   599→    const cachedResult = this.#resolveCache.get(requestKey, parentURL);
   600→    if (cachedResult != null) {
   601→      return cachedResult;
   602→    }
   603→    const result = this.defaultResolve(specifier, parentURL, importAttributes);
   604→    this.#resolveCache.set(requestKey, parentURL, result);
   605→    return result;
   606→  }
   607→
   608→  /**
   609→   * This is the default resolve step for future synchronous hooks, which incorporates asynchronous hooks
   610→   * from module.register() which are run in a blocking fashion for it to be synchronous.
   611→   * @param {string|URL} specifier See {@link resolveSync}.
   612→   * @param {{ parentURL?: string, importAttributes: ImportAttributes}} context See {@link resolveSync}.
   613→   * @returns {{ format: string, url: string }}
   614→   */
   615→  #resolveAndMaybeBlockOnLoaderThread(specifier, context) {
   616→    if (this.#customizations) {
   617→      return this.#customizations.resolveSync(specifier, context.parentURL, context.importAttributes);
   618→    }
   619→    return this.#cachedDefaultResolve(specifier, context.parentURL, context.importAttributes);
   620→  }
