   622→  /**
   623→   * Similar to {@link resolve}, but the results are always synchronously returned. If there are any
   624→   * asynchronous resolve hooks from module.register(), it will block until the results are returned
   625→   * from the loader thread for this to be synchornous.
   626→   * This is here to support `import.meta.resolve()`, `require()` in imported CJS, and
   627→   * future synchronous hooks.
   628→   *
   629→   * TODO(joyeecheung): consolidate the cache behavior and use this in require(esm).
   630→   * @param {string|URL} specifier See {@link resolve}.
   631→   * @param {string} [parentURL] See {@link resolve}.
   632→   * @param {ImportAttributes} [importAttributes] See {@link resolve}.
   633→   * @returns {{ format: string, url: string }}
   634→   */
   635→  resolveSync(specifier, parentURL, importAttributes = { __proto__: null }) {
   636→    return this.#resolveAndMaybeBlockOnLoaderThread(`${specifier}`, { parentURL, importAttributes });
   637→  }
   638→
   639→  /**
   640→   * Our `defaultResolve` is synchronous and can be used in both
   641→   * `resolve` and `resolveSync`. This function is here just to avoid
   642→   * repeating the same code block twice in those functions.
