   644→  defaultResolve(originalSpecifier, parentURL, importAttributes) {
   645→    defaultResolve ??= require('internal/modules/esm/resolve').defaultResolve;
   646→
   647→    const context = {
   648→      __proto__: null,
   649→      conditions: this.#defaultConditions,
   650→      importAttributes,
   651→      parentURL,
   652→    };
