   673→  /**
   674→   * This is the default load step for future synchronous hooks, which incorporates asynchronous hooks
   675→   * from module.register() which are run in a blocking fashion for it to be synchronous.
   676→   * @param {string} url See {@link load}
   677→   * @param {object} context See {@link load}
   678→   * @returns {{ format: ModuleFormat, source: ModuleSource }}
   679→   */
   680→  #loadAndMaybeBlockOnLoaderThread(url, context) {
   681→    if (this.#customizations) {
   682→      return this.#customizations.loadSync(url, context);
   683→    }
   684→    defaultLoadSync ??= require('internal/modules/esm/load').defaultLoadSync;
