   309→ */
   310→class ModuleJobSync extends ModuleJobBase {
   311→  #loader = null;
   312→
   313→  /**
   314→   * @param {ModuleLoader} loader The ESM loader.
   315→   * @param {string} url URL of the module to be wrapped in ModuleJob.
   316→   * @param {ImportAttributes} importAttributes Import attributes from the import statement.
   317→   * @param {ModuleWrap} moduleWrap Translated ModuleWrap for the module.
   318→   * @param {boolean} isMain Whether the module is the entry point.
   319→   * @param {boolean} inspectBrk Whether this module should be evaluated with the
   320→   *                             first line paused in the debugger (because --inspect-brk is passed).
   321→   */
   322→  constructor(loader, url, importAttributes, moduleWrap, isMain, inspectBrk) {
   323→    super(url, importAttributes, isMain, inspectBrk, true);
   324→
   325→    this.#loader = loader;
   326→    this.module = moduleWrap;
   327→
   328→    assert(this.module instanceof ModuleWrap);
   329→    // Store itself into the cache first before linking in case there are circular
   330→    // references in the linking.
   331→    loader.loadCache.set(url, importAttributes.type, this);
   332→
   333→    try {
   334→      const moduleRequests = this.module.getModuleRequests();
   335→      // Specifiers should be aligned with the moduleRequests array in order.
   336→      const specifiers = Array(moduleRequests.length);
   337→      const modules = Array(moduleRequests.length);
   338→      const jobs = Array(moduleRequests.length);
   339→      for (let i = 0; i < moduleRequests.length; ++i) {
   340→        const { specifier, attributes } = moduleRequests[i];
   341→        const job = this.#loader.getModuleJobForRequire(specifier, url, attributes);
   342→        specifiers[i] = specifier;
